import React, {useState} from 'react'
import ReactPlayer from "react-player";
import ScrollAnimation from "react-animate-on-scroll";
import {fadeIn, fadeOut} from "react-animations";
import styled, { keyframes } from 'styled-components';
const Projects = () => {
    const [isShown, SetIsShown] = useState(0);
    const FadeIn = styled.div`animation: 0.5s ${keyframes`${fadeIn}`} 1 `;
    const FadeOut = styled.div`animation: 0.5s ${keyframes`${fadeOut}`} 1 `;
    return(
        <div className="ui center aligned segment">
            <div className="grid">
                <div className="cell"
                     onMouseEnter={() => SetIsShown(1)}
                     onMouseLeave={() => SetIsShown(0)}
                >

                    <ReactPlayer
                        url="./videos/Helicopter_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        controls={true}
                        style={{opacity:isShown ? 0:1}}
                    ></ReactPlayer>
                    }
                    {isShown == 1 && (
                        <div>
                            <FadeIn>
                                <div className="ui white" style={{width: "40vw", height: "40vh"}}></div>
                            </FadeIn>
                        </div>
                    )
                    }


                </div>
                <div className="cell"
                     onMouseEnter={() => SetIsShown(2)}
                     onMouseLeave={() => SetIsShown(0)}
                >
                    {isShown == 0 && (
                        <ReactPlayer
                            url="./videos/Solar_System_Demo.MP4"
                            width='40vw'
                            height='40vh'
                            controls={true}
                        ></ReactPlayer>
                    )

                    }
                    {isShown == 2 && (
                        <FadeIn>
                            <div className="ui white" style={{width: "40vw", height: "40vh"}}></div>
                        </FadeIn>
                    )

                    }


                </div>
            </div>
        </div>
    );
};
export default Projects;
